'use client';

import React, { useState } from 'react';
import { useCart } from '../lib/cart';
import { useAuth } from '../lib/auth';
import { createOrder } from '../lib/db';
import styles from './CartDrawer.module.css';

interface CartDrawerProps {
  onOpenAuth: () => void;
}

export const CartDrawer: React.FC<CartDrawerProps> = ({ onOpenAuth }) => {
  const { cart, totalCost, totalItems, updateQuantity, removeFromCart, clearCart, isCartOpen, setIsCartOpen } = useCart();
  const { user, isAuthenticated } = useAuth();
  const [isSubmitting, setIsSubmitting] = useState(false);

  if (!isCartOpen) return null;

  const handleCheckout = async () => {
    if (!isAuthenticated) {
      setIsCartOpen(false);
      onOpenAuth();
      return;
    }

    setIsSubmitting(true);
    try {
      const orderItems = cart.map((item) => ({
        productId: item.productId,
        quantity: item.quantity,
      }));
      await createOrder(user?.id || null, orderItems);
      alert('Order placed successfully! Thank you.');
      clearCart();
      setIsCartOpen(false);
    } catch (err: any) {
      console.error(err);
      alert(err.message || 'Checkout failed');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className={styles.overlay} onClick={() => setIsCartOpen(false)}>
      <div className={styles.drawer} onClick={(e) => e.stopPropagation()}>
        <div className={styles.header}>
          <h2 className={styles.title}>Your Cart ({totalItems})</h2>
          <button className={styles.closeBtn} onClick={() => setIsCartOpen(false)} aria-label="Close cart">
            &times;
          </button>
        </div>

        <div className={styles.itemsList}>
          {cart.length === 0 ? (
            <div className={styles.emptyState}>
              <p>Your wholesale cart is empty.</p>
              <button className="btn btn-primary" style={{ marginTop: '16px' }} onClick={() => setIsCartOpen(false)}>
                Browse Catalog
              </button>
            </div>
          ) : (
            cart.map((item) => (
              <div key={item.productId} className={styles.itemCard}>
                <div className={styles.itemInfo}>
                  <h3 className={styles.itemName}>{item.name}</h3>
                  <p className={styles.itemCategory}>{item.wholesaler_name || 'Wholesale Goods'}</p>
                  <p className={styles.itemPrice}>${item.price.toFixed(2)} / unit</p>
                </div>
                <div className={styles.itemActions}>
                  <div className={styles.quantityControls}>
                    <button
                      className={styles.qtyBtn}
                      onClick={() => updateQuantity(item.productId, item.quantity - 1)}
                    >
                      -
                    </button>
                    <span className={styles.qtyVal}>{item.quantity}</span>
                    <button
                      className={styles.qtyBtn}
                      disabled={item.quantity >= item.stock_quantity}
                      onClick={() => updateQuantity(item.productId, item.quantity + 1)}
                    >
                      +
                    </button>
                  </div>
                  <button
                    className={styles.removeBtn}
                    onClick={() => removeFromCart(item.productId)}
                    aria-label="Remove item"
                  >
                    Remove
                  </button>
                </div>
              </div>
            ))
          )}
        </div>

        {cart.length > 0 && (
          <div className={styles.footer}>
            <div className={styles.summaryRow}>
              <span>Subtotal</span>
              <span className={styles.totalVal}>${totalCost.toFixed(2)}</span>
            </div>
            <p className={styles.footerNotice}>
              Wholesale pricing applied. Shipping and taxes calculated at checkout.
            </p>
            <button
              className="btn btn-primary"
              style={{ width: '100%', padding: '14px', borderRadius: 'var(--radius-md)' }}
              onClick={handleCheckout}
              disabled={isSubmitting}
            >
              {isSubmitting ? 'Processing Order...' : isAuthenticated ? 'Place Wholesale Order' : 'Sign In to Checkout'}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};
